transform_js:
var months=rawData.months;
var years=rawData.years;
var seriesList=[];
var markLines=[];
months.forEach(function(m){
  var vals=rawData.values[m];
  var points=vals.map(function(v,i){return [m,v];});
  seriesList.push({month:m,points:points,values:vals});
  var avg=vals.reduce(function(s,v){return s+v;},0)/vals.length;
  markLines.push({month:m,avg:avg});
});
transformedData={seriesList:seriesList,markLines:markLines,months:months,years:years};

echarts_js:
var colors=['#5470c6','#91cc75','#fac858'];
var series=[];
transformedData.years.forEach(function(yr,yi){
  var data=[];
  transformedData.months.forEach(function(m){
    data.push([m,transformedData.seriesList.filter(function(s){return s.month===m;})[0].values[yi]]);
  });
  series.push({name:yr,type:'bar',data:data,barGap:'5%',itemStyle:{color:colors[yi]}});
});
var avgData=transformedData.markLines.map(function(ml){return [ml.month,ml.avg];});
series.push({name:'Average',type:'line',data:avgData,symbol:'diamond',symbolSize:8,lineStyle:{color:'#ee6666',width:2,type:'dashed'},itemStyle:{color:'#ee6666'},z:10});
option={title:{text:'Seasonal Trends (Cycle Plot)',left:'center'},tooltip:{trigger:'axis',axisPointer:{type:'shadow'}},legend:{bottom:'3%'},xAxis:{type:'category',data:transformedData.months,axisTick:{alignWithLabel:true}},yAxis:{type:'value',name:'Sales'},series:series};
